import { Link, useNavigate } from 'react-router-dom';

function Navbar() {
  const navigate = useNavigate();
  
  // Get user and token directly from localStorage
  const token = localStorage.getItem('token');
  const userString = localStorage.getItem('user');
  const user = userString ? JSON.parse(userString) : null;

  const handleLogout = () => {
    // Clear localStorage
    localStorage.removeItem('token');
    localStorage.removeItem('user');
    
    // Redirect to login
    navigate('/login');
    
    // Refresh page to update navbar
    window.location.reload();
  };

  // Styles
  const navStyle = {
    background: 'linear-gradient(to right, #3b82f6, #8b5cf6, #ec4899)',
    boxShadow: '0 4px 6px rgba(0, 0, 0, 0.1)',
    position: 'sticky',
    top: 0,
    zIndex: 50,
  };

  const containerStyle = {
    maxWidth: '600px',
    margin: '0 auto',
    padding: '0 1rem',
  };

  const flexStyle = {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'center',
    height: '5rem',
  };

  const logoStyle = {
    display: 'flex',
    alignItems: 'center',
    gap: '0.75rem',
    textDecoration: 'none',
  };

  const logoTextStyle = {
    fontSize: '1.5rem',
    fontWeight: 'bold',
    color: 'white',
  };

  const menuStyle = {
    display: 'flex',
    alignItems: 'center',
    gap: '1.5rem',
  };

  const linkStyle = {
    color: 'white',
    textDecoration: 'none',
    padding: '0.5rem 1rem',
    borderRadius: '0.5rem',
    fontWeight: '500',
    transition: 'all 0.3s',
  };

  const linkHoverStyle = {
    background: 'rgba(255, 255, 255, 0.2)',
  };

  const buttonStyle = {
    background: 'white',
    color: '#8b5cf6',
    padding: '0.5rem 1.5rem',
    borderRadius: '9999px',
    border: 'none',
    fontWeight: '600',
    cursor: 'pointer',
    transition: 'all 0.3s',
    textDecoration: 'none',
    display: 'inline-block',
  };

  const logoutButtonStyle = {
    ...buttonStyle,
    background: '#ef4444',
    color: 'white',
  };

  const userNameStyle = {
    color: 'white',
    padding: '0.5rem 1rem',
    fontWeight: '500',
    background: 'rgba(255, 255, 255, 0.2)',
    borderRadius: '9999px',
  };

  return (
    <nav style={navStyle}>
      <div style={containerStyle}>
        <div style={flexStyle}>
          
          {/* Logo */}
          <Link to="/" style={logoStyle}>
            <span style={{ fontSize: '2rem' }}>🎉</span>
            <span style={logoTextStyle}>EventHub</span>
          </Link>

          {/* Desktop Menu */}
          <div style={menuStyle}>
            <Link 
              to="/" 
              style={linkStyle}
              onMouseEnter={(e) => e.target.style.background = linkHoverStyle.background}
              onMouseLeave={(e) => e.target.style.background = 'transparent'}
            >
              Home
            </Link>
            
            <Link 
              to="/events" 
              style={linkStyle}
              onMouseEnter={(e) => e.target.style.background = linkHoverStyle.background}
              onMouseLeave={(e) => e.target.style.background = 'transparent'}
            >
              Events
            </Link>

            {token ? (
              <>
                {/* Logged In User Menu */}
                <Link 
                  to="/my-bookings" 
                  style={linkStyle}
                  onMouseEnter={(e) => e.target.style.background = linkHoverStyle.background}
                  onMouseLeave={(e) => e.target.style.background = 'transparent'}
                >
                  My Bookings
                </Link>

                {user && user.role === 'admin' && (
                  <Link 
                    to="/admin" 
                    style={linkStyle}
                    onMouseEnter={(e) => e.target.style.background = linkHoverStyle.background}
                    onMouseLeave={(e) => e.target.style.background = 'transparent'}
                  >
                    Admin
                  </Link>
                )}

                <span style={userNameStyle}>
                  👤 {user?.name || 'User'}
                </span>

                <button 
                  onClick={handleLogout} 
                  style={logoutButtonStyle}
                  onMouseEnter={(e) => e.target.style.background = '#dc2626'}
                  onMouseLeave={(e) => e.target.style.background = '#ef4444'}
                >
                  Logout
                </button>
              </>
            ) : (
              <>
                {/* Logged Out Menu */}
                <Link 
                  to="/login" 
                  style={linkStyle}
                  onMouseEnter={(e) => e.target.style.background = linkHoverStyle.background}
                  onMouseLeave={(e) => e.target.style.background = 'transparent'}
                >
                  Login
                </Link>
                
                <Link to="/register" style={buttonStyle}>
                  Sign Up Free
                </Link>
              </>
            )}
          </div>
        </div>
      </div>
    </nav>
  );
}

export default Navbar;
